from pydantic import BaseModel, Field, field_validator
from typing import Literal
import json

class SearchInput(BaseModel):
    query: str = Field(description="Search terms")
    max_results: int = Field(default=10, ge=1, le=100)
    sort: Literal["relevance", "date", "popularity"] = "relevance"
    include_archived: bool = False
    tags: list[str] = Field(default_factory=list)

    @field_validator("query")
    @classmethod
    def query_not_empty(cls, v: str) -> str:
        if not v.strip():
            raise ValueError("query must not be blank")
        return v.strip()

def search(raw_input: dict) -> str:
    try:
        args = SearchInput.model_validate(raw_input)
    except Exception as exc:
        return json.dumps({"error": f"Invalid arguments: {exc}"})

    # Now args is fully typed — IDE autocomplete, mypy, etc. work
    results = _run_search(
        query=args.query,
        limit=args.max_results,
        sort_by=args.sort,
        include_archived=args.include_archived,
        tags=args.tags,
    )
    return json.dumps({"results": results, "total": len(results)})

# Unsafe — KeyError if 'units' was not generated
def bad_dispatch(raw: dict) -> str:
    city = raw["city"]
    units = raw["units"]   # ← crashes if model omitted optional arg
    return get_weather(city, units)

# Safe with .get() + default
def ok_dispatch(raw: dict) -> str:
    city = raw["city"]
    units = raw.get("units", "celsius")
    return get_weather(city, units)

# Best — Pydantic default handles it, plus type safety
class WeatherInput(BaseModel):
    city: str
    units: str = "celsius"

def best_dispatch(raw: dict) -> str:
    args = WeatherInput.model_validate(raw)
    return get_weather(args.city, args.units)

from typing import Any, Callable, TypeVar
from pydantic import BaseModel
import json

M = TypeVar("M", bound=BaseModel)

def make_handler(model_cls: type[M], fn: Callable[[M], str]):
    def handler(raw: dict[str, Any]) -> str:
        try:
            args = model_cls.model_validate(raw)
        except Exception as exc:
            return json.dumps({"error": str(exc)})
        return fn(args)
    return handler

# --- Define models ---
class WeatherInput(BaseModel):
    city: str
    units: str = "celsius"

class SearchInput(BaseModel):
    query: str
    max_results: int = 10

class BookInput(BaseModel):
    activity: str
    date: str   # YYYY-MM-DD

# --- Implementations ---
def impl_weather(args: WeatherInput) -> str:
    return json.dumps({"temp": 22, "condition": "clear", "units": args.units})

def impl_search(args: SearchInput) -> str:
    return json.dumps({"results": [f"result for {args.query}"] * args.max_results})

def impl_book(args: BookInput) -> str:
    return json.dumps({"confirmed": True, "activity": args.activity, "date": args.date})

# --- Dispatch table ---
HANDLERS: dict[str, Callable[[dict], str]] = {
    "get_weather":       make_handler(WeatherInput, impl_weather),
    "search":            make_handler(SearchInput, impl_search),
    "book_reservation":  make_handler(BookInput, impl_book),
}

def dispatch_tool(name: str, raw_input: dict) -> str:
    handler = HANDLERS.get(name)
    if handler is None:
        return json.dumps({"error": f"Unknown tool: {name}"})
    return handler(raw_input)

