from dataclasses import dataclass, field
from typing import Optional
import dacite, json

@dataclass
class WeatherInput:
    city: str
    units: str = "celsius"

@dataclass
class PaginationInput:
    page: int
    page_size: int = 20

@dataclass
class SearchInput:
    query: str
    max_results: int = 10
    pagination: Optional[PaginationInput] = None
    tags: list[str] = field(default_factory=list)

def dispatch_tool(name: str, raw: dict) -> str:
    try:
        if name == "get_weather":
            args = dacite.from_dict(WeatherInput, raw)
            return get_weather(args.city, args.units)
        if name == "search":
            args = dacite.from_dict(SearchInput, raw)
            return search(args.query, args.max_results)
    except dacite.DaciteError as exc:
        return json.dumps({"error": str(exc)})
    return json.dumps({"error": f"Unknown tool: {name}"})

from pydantic import BaseModel, Field
from typing import Optional

class DateRange(BaseModel):
    start: str   # ISO 8601, e.g. "2024-01-01"
    end: str

class Filter(BaseModel):
    field: str
    operator: str = "eq"   # eq, ne, gt, lt, contains
    value: str

class ReportInput(BaseModel):
    report_type: str
    date_range: DateRange
    filters: list[Filter] = Field(default_factory=list)
    limit: Optional[int] = None

