from pydantic import ValidationError
import json

def safe_dispatch(name: str, raw: dict) -> dict:
    """
    Returns: {"content": str, "is_error": bool}
    Caller should pass is_error=True to tool_result when is_error is True.
    """
    handler = HANDLERS.get(name)
    if handler is None:
        return {
            "content": json.dumps({"error": "unknown_tool", "name": name}),
            "is_error": True,
        }
    try:
        return {"content": handler(raw), "is_error": False}
    except ValidationError as exc:
        # Pydantic validation failure — structured field-level errors
        errors = [
            {"field": ".".join(str(l) for l in e["loc"]), "msg": e["msg"]}
            for e in exc.errors()
        ]
        return {
            "content": json.dumps({"error": "invalid_arguments", "details": errors}),
            "is_error": True,
        }
    except Exception as exc:
        return {
            "content": json.dumps({"error": "tool_execution_failed", "message": str(exc)}),
            "is_error": True,
        }

